        assert_eq!(engine.windows.len(), 2);

        // Ctrl-W v should split vertically
        press_ctrl(&mut engine, 'w');
        press_char(&mut engine, 'v');
        assert_eq!(engine.windows.len(), 3);

        // Ctrl-W w should cycle
        let before = engine.active_window_id();
