        press_char(&mut engine, 'w'); // cursor moves to 'f' (start of "foo")

        press_char(&mut engine, 'y');

        // Visual mode is inclusive, so we get from 'h' to 'f' inclusive
        let (content, _) = engine.registers.get(&'"').unwrap();
