        press_char(&mut engine, 'a');

        // Set mark 'b' at line 3
        press_char(&mut engine, 'j');
        press_char(&mut engine, 'j');
        press_char(&mut engine, 'm');
        press_char(&mut engine, 'b');

        // Jump to mark 'a'
        press_char(&mut engine, '\'');
